+    /**
+     * @return true if this VM is using the -XX:AOTCache flag
+     */
+    protected String vmCDSUsingAOTCodeCaching() {
+        if ("true".equals(vmCDSSupportsAOTCodeCaching()) && allFlags().anyMatch(s -> s.startsWith("-XX:AOTCache"))) {
+            return "true";
+        } else {
+            return "false";
+        }
+    }
